-- Generated by tools/portable_aliases/generate.py.
-- Proves each portable alias shares the operator's exact C
-- implementation.  Expected output: 'PORTABLE ALIASES OK'.
WITH mismatch AS (
  SELECT a.proname, a.oid
  FROM pg_proc a JOIN pg_proc b ON a.prosrc <> b.prosrc
  JOIN pg_operator o ON o.oprcode = b.oid
  WHERE a.proname IN ('above', 'adjacent', 'after', 'back', 'before', 'below', 'contained', 'contains', 'front', 'left', 'overabove', 'overafter', 'overback', 'overbefore', 'overbelow', 'overfront', 'overlaps', 'overleft', 'overright', 'right', 'same', 'teq', 'tge', 'tgt', 'tle', 'tlt', 'tne')
  AND a.proargtypes = b.proargtypes
  AND o.oprname = ANY (ARRAY['#&>', '#<', '#<=', '#<>', '#=', '#>', '#>=', '#>>', '&&', '&<#', '&<', '&</', '&<|', '&>', '-|-', '/&>', '/>>', '<<#', '<<', '<</', '<<|', '<@', '>>', '@>', '|&>', '|>>', '~='])
)
SELECT CASE WHEN count(*) = 0 THEN 'PORTABLE ALIASES OK'
  ELSE 'MISMATCH: '||count(*)||' alias(es) differ from operator impl' END AS result
FROM mismatch;
